import { AgentClient } from '@azure/ai-projects';
import { VexClient } from 'vex-sdk-ts';

const client = new AgentClient('https://your-project.openai.azure.com/', credential);
const vex = new VexClient({ apiKey: 'vex-api-key' });

async function executeWorkflow(threadId: string, step: number) {
  const run = await client.beta.threads.runs.create(threadId, {
    assistant_id: 'agent-id',
    instructions: `Execute workflow step ${step}: check conditions and branch appropriately`
  });

  while (run.status === 'in_progress' || run.status === 'requires_action') {
    await new Promise(r => setTimeout(r, 1000));
    const updatedRun = await client.beta.threads.runs.retrieve(threadId, run.id);

    if (updatedRun.status === 'requires_action') {
      const validated = await vex.validateAction(
        updatedRun.required_action.submit_tool_outputs.tool_calls
      );
      await client.beta.threads.runs.submitToolOutputs(threadId, run.id, validated);
    }
  }
}

import { AgentClient } from '@azure/ai-projects';
import { VexClient } from 'vex-sdk-ts';

const vex = new VexClient({ apiKey: 'vex-api-key' });

interface ToolCall { tool_call_id: string; function: { name: string; arguments: string } }

async function idempotentToolExecution(
  client: AgentClient,
  threadId: string,
  runId: string,
  toolCalls: ToolCall[]
): Promise<any> {
  const validatedCalls = [];

  for (const toolCall of toolCalls) {
    // Check idempotency key
    const idempotent = await vex.checkIdempotency(
      toolCall.function.name,
      JSON.parse(toolCall.function.arguments)
    );

    if (idempotent.isSafe) {
      validatedCalls.push(toolCall);
    } else {
      console.log(`Skipping duplicate: ${toolCall.tool_call_id}`);
    }
  }

  return client.beta.threads.runs.submitToolOutputs(threadId, runId, {
    tool_outputs: validatedCalls.map(call => ({
      tool_call_id: call.tool_call_id,
      output: 'IDEMPOTENT_SKIP'
    }))
  });
}

