from vex_sdk import VexClient
from azure.ai.projects.types import RunObject

vex = VexClient(api_key="your-vex-key")

def vex_policy_middleware(run: RunObject) -> RunObject:
    if run.status == "requires_action":
        tool_calls = run.required_action.submit_tool_outputs.tool_calls

        validated_tools = []
        for tool in tool_calls:
            # Validate against enterprise policies
            validation = vex.validate_tool(
                tool.function.name,
                tool.function.arguments,
                policies={
                    "pii_detection": "block",
                    "data_classification": "confidential"
                }
            )

            if validation.approved:
                validated_tools.append({
                    "tool_call_id": tool.id,
                    "output": tool.function.arguments  # Execute
                })
            else:
                validated_tools.append({
                    "tool_call_id": tool.id,
                    "output": f"BLOCKED: {validation.reason}"
                })

        run.required_action.submit_tool_outputs.tool_outputs = validated_tools

    return run

import { VexClient } from 'vex-sdk-ts';

const vex = new VexClient({ apiKey: 'vex-api-key' });

async function monitorThreadTokens(
  client: any,
  threadId: string,
  tokenLimit: number = 128000
): Promise<boolean> {
  const thread = await client.beta.threads.retrieve(threadId);
  const usage = await vex.analyzeThreadUsage(thread);

  if (usage.total_tokens > tokenLimit * 0.8) {
    // Trigger summarization and checkpoint
    await vex.summarizeThread(threadId, {
      max_tokens: 4000,
      preserve: ['key_decisions', 'pending_actions']
    });

    // Notify and offer rollback
    console.warn('Token limit approaching - thread summarized');
    return false;
  }

  return true;
}

// Usage in run loop
while (run.status === 'in_progress') {
  if (!(await monitorThreadTokens(client, threadId))) {
    break;
  }
}
